DROP TABLE IF EXISTS `case_info`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `case_info` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '案件ID',
  `case_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '案件编号，提交后生成',
  `case_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '案件标题',
  `case_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '案件类型',
  `case_status` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'DRAFT' COMMENT '案件状态',
  `current_node_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '当前节点编码',
  `current_node_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '当前节点名称',
  `current_handler_id` bigint DEFAULT NULL COMMENT '当前承办人ID',
  `current_handler_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '当前承办人姓名',
  `accept_dept_id` bigint DEFAULT NULL COMMENT '承办部门ID',
  `accept_dept_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '承办部门名称',
  `entrust_org_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '委托单位名称',
  `entrust_contact_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '委托联系人',
  `entrust_contact_phone` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '委托联系人电话',
  `entrust_date` date DEFAULT NULL COMMENT '委托日期',
  `accepted_time` datetime DEFAULT NULL COMMENT '受理时间',
  `deadline_time` datetime DEFAULT NULL COMMENT '办理截止时间',
  `urgent_flag` tinyint NOT NULL DEFAULT '0' COMMENT '是否加急：0否 1是',
  `overtime_flag` tinyint NOT NULL DEFAULT '0' COMMENT '是否超时：0否 1是',
  `submitted_time` datetime DEFAULT NULL COMMENT '提交时间',
  `completed_time` datetime DEFAULT NULL COMMENT '办结时间',
  `archived_time` datetime DEFAULT NULL COMMENT '归档时间',
  `terminated_time` datetime DEFAULT NULL COMMENT '终止时间',
  `remark` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `version` int NOT NULL DEFAULT '0' COMMENT '乐观锁版本号',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人ID',
  `updated_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除：0否 1是',
  `form_data` json DEFAULT NULL COMMENT '案件最新的表单数据',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_case_info_case_no` (`case_no`),
  KEY `idx_case_info_status` (`case_status`),
  KEY `idx_case_info_current_node` (`current_node_code`),
  KEY `idx_case_info_handler` (`current_handler_id`),
  KEY `idx_case_info_accept_dept` (`accept_dept_id`),
  KEY `idx_case_info_created_time` (`created_time`),
  KEY `idx_case_info_deadline_time` (`deadline_time`),
  KEY `idx_case_info_entrust_org` (`entrust_org_name`)
) ENGINE=InnoDB AUTO_INCREMENT=1681 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='案件主表';
