--
-- Table structure for table `case_material`
--

DROP TABLE IF EXISTS `case_material`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `case_material` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '材料ID',
  `case_id` bigint NOT NULL COMMENT '案件ID',
  `material_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '材料编号',
  `material_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '材料名称',
  `material_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '材料类型',
  `source_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '来源类型',
  `receive_time` datetime DEFAULT NULL COMMENT '接收时间',
  `receive_user_id` bigint DEFAULT NULL COMMENT '接收人ID',
  `receive_user_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '接收人姓名',
  `status` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'received' COMMENT '材料状态',
  `current_holder_id` bigint DEFAULT NULL COMMENT '当前持有人ID',
  `current_holder_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '当前持有人姓名',
  `quantity` int DEFAULT NULL COMMENT '数量',
  `remark` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人ID',
  `updated_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除：0否 1是',
  PRIMARY KEY (`id`),
  KEY `idx_case_material_case_id` (`case_id`),
  KEY `idx_case_material_no` (`material_no`),
  KEY `idx_case_material_status` (`status`),
  KEY `idx_case_material_holder` (`current_holder_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='案件材料台账表';
/*!40101 SET character_set_client = @saved_cs_client */;

