--
-- Table structure for table `case_node_instance`
--

DROP TABLE IF EXISTS `case_node_instance`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `case_node_instance` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '节点实例ID',
  `case_id` bigint NOT NULL COMMENT '案件ID',
  `wf_instance_id` bigint DEFAULT NULL COMMENT '主流程实例ID',
  `subflow_instance_id` bigint DEFAULT NULL COMMENT '子流程实例ID',
  `node_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '节点编码',
  `node_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '节点名称',
  `status` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'running' COMMENT '节点状态：running/completed/cancelled',
  `started_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '开始时间',
  `completed_time` datetime DEFAULT NULL COMMENT '完成时间',
  `handler_id` bigint DEFAULT NULL COMMENT '节点实际办理人ID',
  `handler_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '节点实际办理人姓名',
  `result_action` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '完成动作',
  `result_opinion` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '办理意见',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `form_data` json DEFAULT NULL COMMENT '节点完成时的表单数据快照',
  PRIMARY KEY (`id`),
  KEY `idx_case_node_case_id` (`case_id`),
  KEY `idx_case_node_wf_instance` (`wf_instance_id`),
  KEY `idx_case_node_subflow` (`subflow_instance_id`),
  KEY `idx_case_node_node_code` (`node_code`),
  KEY `idx_case_node_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=33295 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='案件节点实例表';
/*!40101 SET character_set_client = @saved_cs_client */;

