--
-- Table structure for table `case_task`
--

DROP TABLE IF EXISTS `case_task`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `case_task` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '任务ID',
  `case_id` bigint NOT NULL COMMENT '案件ID',
  `wf_instance_id` bigint DEFAULT NULL COMMENT '主流程实例ID',
  `subflow_instance_id` bigint DEFAULT NULL COMMENT '子流程实例ID',
  `node_instance_id` bigint NOT NULL COMMENT '节点实例ID',
  `task_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '任务类型：single/candidate/parallel',
  `task_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '任务标题',
  `node_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '节点编码',
  `node_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '节点名称',
  `status` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'pending' COMMENT '任务状态',
  `assignee_id` bigint DEFAULT NULL COMMENT '办理人ID',
  `assignee_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '办理人姓名',
  `claimed_by` bigint DEFAULT NULL COMMENT '认领人ID',
  `claimed_time` datetime DEFAULT NULL COMMENT '认领时间',
  `started_time` datetime DEFAULT NULL COMMENT '开始办理时间',
  `completed_time` datetime DEFAULT NULL COMMENT '完成时间',
  `deadline_time` datetime DEFAULT NULL COMMENT '截止时间',
  `overtime_flag` tinyint NOT NULL DEFAULT '0' COMMENT '是否超时：0否 1是',
  `result_action` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '完成动作',
  `result_opinion` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '办理意见',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人ID',
  `updated_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `version` int NOT NULL DEFAULT '0' COMMENT '乐观锁版本号',
  PRIMARY KEY (`id`),
  KEY `idx_case_task_case_id` (`case_id`),
  KEY `idx_case_task_assignee_status` (`assignee_id`,`status`),
  KEY `idx_case_task_node_instance` (`node_instance_id`),
  KEY `idx_case_task_status` (`status`),
  KEY `idx_case_task_deadline` (`deadline_time`),
  KEY `idx_case_task_created_time` (`created_time`)
) ENGINE=InnoDB AUTO_INCREMENT=31118 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='案件任务表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `case_task`
--

