DROP TABLE IF EXISTS `case_task_candidate`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `case_task_candidate` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '候选ID',
  `task_id` bigint NOT NULL COMMENT '任务ID',
  `case_id` bigint NOT NULL COMMENT '案件ID',
  `candidate_user_id` bigint DEFAULT NULL COMMENT '候选用户ID',
  `candidate_dept_id` bigint DEFAULT NULL COMMENT '候选部门ID',
  `candidate_post_id` bigint DEFAULT NULL COMMENT '候选岗位ID',
  `candidate_role_id` bigint DEFAULT NULL COMMENT '候选角色ID',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_task_candidate_task_id` (`task_id`),
  KEY `idx_task_candidate_case_id` (`case_id`),
  KEY `idx_task_candidate_user` (`candidate_user_id`),
  KEY `idx_task_candidate_dept_post` (`candidate_dept_id`,`candidate_post_id`),
  KEY `idx_task_candidate_role` (`candidate_role_id`)
) ENGINE=InnoDB AUTO_INCREMENT=29490 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='任务候选人表';
