DROP TABLE IF EXISTS `knowledge_document_version`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `knowledge_document_version` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '知识文档版本ID',
  `document_id` bigint NOT NULL COMMENT '文档ID',
  `version_no` int NOT NULL COMMENT '版本号',
  `file_id` bigint DEFAULT NULL COMMENT '文件ID',
  `form_snapshot_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '表单快照JSON',
  `archive_result_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '归档结果JSON',
  `change_note` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '变更说明',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_knowledge_document_version` (`document_id`,`version_no`),
  KEY `idx_knowledge_document_version_file` (`file_id`)
) ENGINE=InnoDB AUTO_INCREMENT=24279 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='知识库文档版本表';
