--
-- Table structure for table `wf_node_def`
--

DROP TABLE IF EXISTS `wf_node_def`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `wf_node_def` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '节点定义ID',
  `wf_id` bigint NOT NULL COMMENT '流程定义ID',
  `node_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '节点编码',
  `node_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '节点名称',
  `node_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '节点类型：start/task/review/parallel/end',
  `task_type` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'single' COMMENT '任务类型：single/candidate/parallel',
  `case_status` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '进入该节点时案件状态',
  `handler_dept_rule` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '承办部门规则',
  `handler_post_rule` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '承办岗位规则',
  `handler_role_rule` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '承办角色规则',
  `allow_manual_assign` tinyint NOT NULL DEFAULT '0' COMMENT '是否允许人工指定承办人',
  `timeout_hours` int DEFAULT NULL COMMENT '节点超时时限小时数',
  `config_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '节点扩展配置JSON',
  `assignee_rule_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '办理人规则JSON',
  `form_rule_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '表单字段权限/规则JSON',
  `permission_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '节点权限JSON',
  `sort_no` int NOT NULL DEFAULT '0' COMMENT '排序号',
  `enabled` tinyint NOT NULL DEFAULT '1' COMMENT '是否启用：0否 1是',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人ID',
  `updated_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除：0否 1是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_wf_node_def_wf_node` (`wf_id`,`node_code`),
  KEY `idx_wf_node_def_wf_id` (`wf_id`),
  KEY `idx_wf_node_def_node_type` (`node_type`),
  KEY `idx_wf_node_def_enabled` (`enabled`)
) ENGINE=InnoDB AUTO_INCREMENT=572206 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='流程节点定义表';
/*!40101 SET character_set_client = @saved_cs_client */;

