--
-- Table structure for table `wf_transition_def`
--

DROP TABLE IF EXISTS `wf_transition_def`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `wf_transition_def` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '流转定义ID',
  `wf_id` bigint NOT NULL COMMENT '流程定义ID',
  `from_node_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '来源节点编码',
  `to_node_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '目标节点编码',
  `action_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '动作编码',
  `action_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '动作名称',
  `require_reason` tinyint NOT NULL DEFAULT '0' COMMENT '是否必须填写原因：0否 1是',
  `require_opinion` tinyint NOT NULL DEFAULT '0' COMMENT '是否必须填写意见：0否 1是',
  `condition_expression` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '条件表达式',
  `transition_config_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '流转扩展配置JSON',
  `enabled` tinyint NOT NULL DEFAULT '1' COMMENT '是否启用：0否 1是',
  `sort_no` int NOT NULL DEFAULT '0' COMMENT '排序号',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人ID',
  `updated_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除：0否 1是',
  PRIMARY KEY (`id`),
  KEY `idx_wf_transition_wf_from` (`wf_id`,`from_node_code`),
  KEY `idx_wf_transition_wf_action` (`wf_id`,`action_code`),
  KEY `idx_wf_transition_enabled` (`enabled`)
) ENGINE=InnoDB AUTO_INCREMENT=818775 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='流程流转定义表';
/*!40101 SET character_set_client = @saved_cs_client */;

